#include <bits/stdc++.h>
using namespace std;


void solve(long long N, std::vector<long long> A){
    long long sum=0,countn=0,countmin=10000000000000;
    for(int i=0;i<N;i++){
        if(countmin>abs(A[i])){
            countmin=abs(A[i]);
        }
        if(A[i]>0){
            sum+=A[i];
        }else if(A[i]<0){
            sum-=A[i];
            countn++;
        }
    }
    if(countn%2==0){
        printf("%lld\n",sum);
    }else{
        printf("%lld\n",sum-countmin*2);
    }

}

// Generated by 1.1.4 https://github.com/kyuridenamida/atcoder-tools  (tips: You use the default template now. You can remove this line by using your custom template)
int main(){
    long long N;
    scanf("%lld",&N);
    std::vector<long long> A(N);
    for(int i = 0 ; i < N ; i++){
        scanf("%lld",&A[i]);
    }
    solve(N, std::move(A));
    return 0;
}
